mapper.select:
${pagingTop} SELECT homepage_id, popup_zone_idx, popup_zone_name, popup_zone_seq, use_yn, content, add_date, start_date, end_date, img_file_name, real_file_name, file_extension, file_size, link_url, link_target, popup_zone_type FROM CMS_POPUP_ZONE WHERE homepage_id = #{homepage_id}
AND ${search_type} LIKE '%'||#{search_text}||'%'
ORDER BY popup_zone_seq ASC, add_date DESC ${pagingBottom}

SELECT homepage_id, popup_zone_idx, popup_zone_name, popup_zone_seq, use_yn, content, add_date, start_date, end_date, img_file_name, real_file_name, file_extension, file_size, link_url, link_target, popup_zone_type FROM CMS_POPUP_ZONE WHERE homepage_id = #{homepage_id} AND use_yn = 'Y' AND start_date <= TO_CHAR(SYSDATE, 'yyyy-mm-dd') AND end_date >= TO_CHAR(SYSDATE, 'yyyy-mm-dd')
AND popup_zone_type = #{popup_zone_type}
ORDER BY popup_zone_seq ASC, add_date DESC

mapper.insert:
SELECT NVL(MAX(popup_zone_idx),0)+1 FROM CMS_POPUP_ZONE WHERE homepage_id = #{homepage_id}
INSERT INTO CMS_POPUP_ZONE ( homepage_id, popup_zone_idx, popup_zone_name, popup_zone_seq, use_yn, add_date, start_date, end_date, link_url, link_target, content
, popup_zone_type
, img_file_name, real_file_name, file_extension, file_size
) VALUES ( #{homepage_id}, #{popup_zone_idx}, #{popup_zone_name}, #{popup_zone_seq}, #{use_yn}, SYSDATE, #{start_date}, #{end_date}, #{link_url}, #{link_target}, #{content}
, #{popup_zone_type}
, #{img_file_name}, #{real_file_name}, #{file_extension}, #{file_size}
)

mapper.update:
UPDATE CMS_POPUP_ZONE SET
	popup_zone_name = #{popup_zone_name},
	use_yn = #{use_yn},
	start_date = #{start_date},
	end_date = #{end_date},
	popup_zone_seq = #{popup_zone_seq},
	link_url = #{link_url},
	link_target = #{link_target}

	, popup_zone_type = #{popup_zone_type}

	, content = #{content}

	, img_file_name = #{img_file_name}
	, real_file_name = #{real_file_name}
	, file_extension = #{file_extension}
	, file_size = #{file_size}

WHERE
	homepage_id = #{homepage_id} AND
	popup_zone_idx = #{popup_zone_idx}

UPDATE
	CMS_POPUP_ZONE
SET
	popup_zone_seq = #{popup_zone_seq}
WHERE
	homepage_id = #{homepage_id}
AND	popup_zone_idx = #{popup_zone_idx}
